import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function scoreNFTLiquidity(chainName, collectionAddress) {
  const resp = await client.NftService.getNftTransactionsForContractTokenId(
    chainName, collectionAddress, "1"
  );
  const txns = resp.data?.items ?? [];
  const salesLast30d = txns.filter(tx => {
    const age = Date.now() - new Date(tx.block_signed_at).getTime();
    return age < 30 * 24 * 60 * 60 * 1000;
  });
  const liquidityScore = Math.min(100, salesLast30d.length * 10);
  return { collectionAddress, liquidityScore, salesLast30d: salesLast30d.length };
}
